	if _, statErr := os.Stat(outputFile); os.IsNotExist(statErr) {
		return outputStr, fmt.Errorf("command executed successfully but output file was not created at %s", outputFile)
	}

	return outputStr, nil
}

func main() {
	// Example usage
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		os.Exit(1)
	}

	lbName := os.Args[1]
	outFile := os.Args[2]

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
