	// Instead of using a shell (sh -c) which is prone to injection, we construct the pipeline
	// by chaining commands directly using the os/exec package.
	// Arguments are passed as separate strings, ensuring they are treated as data, not code.

	// Step A: Run `aliyun slb DescribeLoadBalancers`
	// We pass the filter argument securely.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture the stdout of the aliyun command to pass to jq
	var aliyunOutBuf bytes.Buffer
	aliyunCmd.Stdout = &aliyunOutBuf
	aliyunCmd.Stderr = os.Stderr // Forward errors to the user's terminal

	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Step B: Run `jq` to process the output
	// We use the format string compatible with the target command.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the output of aliyun to the input of jq
	jqCmd.Stdin = &aliyunOutBuf

	// Capture the final output of jq
	var jqOutBuf bytes.Buffer
	jqCmd.Stdout = &jqOutBuf
	jqCmd.Stderr = os.Stderr

	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill() // Cleanup if jq fails to start
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to finish
	if err := aliyunCmd.Wait(); err != nil {
		// If aliyun fails, jq might fail too, but we report the aliyun error first
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	finalOutput := jqOutBuf.String()

	// 3. Secure File Writing
