// isValidInput checks if the input string contains only safe characters.
// This prevents command injection and ensures file paths are valid.
func isValidInput(s string) bool {
	// Allow alphanumeric, hyphens, underscores, dots, and forward slashes (for paths)
	// This is a whitelist approach, which is safer than a blacklist.
	for _, r := range s {
		if !((r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') ||
			r == '-' || r == '_' || r == '.' || r == '/') {
			return false
		}
	}
	return true
