package main

import (
	"bytes"
	"fmt"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and formats the output using jq, saving it to the specified output file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs to prevent command injection
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Construct the command pipeline: aliyun ... | jq ... > ...
	// We use 'sh -c' to execute the pipeline because Go's exec package
	// does not natively support shell pipelines.
	// Note: The '>' redirection is handled by the shell.
	command := fmt.Sprintf(
		"aliyun slb DescribeLoadBalancers --LoadBalancerName '%s' | jq '.LoadBalancers.LoadBalancer[]' > '%s'",
		loadBalancerName,
		outputFile,
	)

	// Create the command to run in a shell
	cmd := exec.Command("sh", "-c", command)

	// Capture standard output and standard error
	var stdout bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Execute the command
	err := cmd.Run()
	if err != nil {
		// Return the error combined with stderr output for better debugging
		return stdout.String(), fmt.Errorf("command execution failed: %w (stderr: %s)", err, stderr.String())
	}

	// Return the standard output and nil error
	return stdout.String(), nil
}

func main() {
	// Example usage of the function
	// In a real application, these values would likely come from flags or configuration
	loadBalancerName := "my-load-balancer" // Replace with actual name or input
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Successfully executed query. Output: %s\n", result)
}

