package main

import (
	"bytes"
	"fmt"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Security Fix:
	// 1. Removed shell injection vulnerabilities by avoiding shell interpretation.
	//    - Instead of using `sh -c` with a concatenated command string, we use `exec.Command`
	//      with arguments separated. This prevents the shell from interpreting special characters
	//      in `loadBalancerName` or `outputFile`.
	// 2. Removed unsafe shell redirection (`>`).
	//    - Instead of relying on the shell to redirect output to a file (which could be exploited
	//      to overwrite arbitrary files), we capture the standard output of the `jq` command
	//      and write it to the file using Go's `os` package. This ensures the output is written
	//      strictly to the intended `outputFile` path.

	// Step 1: Run `aliyun slb DescribeLoadBalancers`
	// We pass the loadBalancerName as a direct argument to the aliyun CLI.
	// Note: If the name contains spaces or special characters, the CLI argument parser
	// handles them correctly without shell interpretation.
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture the standard output of the aliyun command to pass to jq
	var aliyunOutput bytes.Buffer
	aliyunCmd.Stdout = &aliyunOutput
	aliyunCmd.Stderr = nil // We handle errors after execution

	// Run the aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %w", err)
	}

	// Step 2: Run `jq` to process the output
	// We pass the captured output from aliyun to jq's standard input.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's output to jq's input
	jqCmd.Stdin = &aliyunOutput

	// Capture jq's output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput
	jqCmd.Stderr = nil

	// Run the jq command
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute jq command: %w", err)
	}

	// Step 3: Write the result to the specified output file
	// We use os.WriteFile which creates or truncates the file securely within the process.
	// This prevents shell redirection vulnerabilities (e.g., `> /etc/passwd`).
	err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the processed JSON content as a string
	return jqOutput.String(), nil
}

