package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"strings"
)

// QuerySLBAndExport runs the aliyun command to query SLB information and exports it to a file using jq.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the aliyun command arguments
	// Command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunArgs := []string{
		"slb",
		"DescribeLoadBalancers",
		fmt.Sprintf("--LoadBalancerName=%s", loadBalancerName),
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", aliyunArgs...)

	// Create the jq command
	// Command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create the tee command to write to the output file
	// Command: tee > outputFile
	// Note: We use a custom writer approach or standard shell redirection logic.
	// Since we need to capture the output as a string AND write to a file, 
	// we can use a bytes.Buffer to capture the final output and write to the file manually,
	// or use the shell pipe if running in a shell environment.
	// To ensure compatibility and avoid shell injection, we will chain the commands using StdoutPipe.

	// Pipe aliyun stdout to jq stdin
	stdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get aliyun stdout pipe: %w", err)
	}
	jqCmd.Stdin = stdout

	// Buffer to capture jq output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill() // Cleanup if jq fails to start
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to finish
	// Order matters: wait for jq first, then aliyun
	if err := jqCmd.Wait(); err != nil {
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Get the result string
	result := strings.TrimSpace(jqOutput.String())

	// Write the result to the output file
	// We use os.WriteFile to handle the "tee" functionality to the specific file.
	// This is safer and more idiomatic in Go than invoking 'tee' via exec.
	if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
		return result, fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	return result, nil
}

func main() {
	// Example usage
	// In a real scenario, these would likely come from command-line flags or arguments.
	// For this executable code, we will use placeholders.

	lbName := "my-load-balancer" // Replace with actual name or fetch from args
	outFile := "output.json"

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Successfully queried SLB and exported to %s.\nResult preview:\n%s\n", outFile, result)
}

