	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get stdout pipe for aliyun command: %w", err)
	}

	// Set the stdin of jq to the stdout of aliyun
	jqCmd.Stdin = aliyunOut

	// Create a buffer to capture the final output of the pipeline
	var outBuf bytes.Buffer
	jqCmd.Stdout = &outBuf

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// Ensure aliyun command is killed if jq fails to start
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for the jq command to finish
	// This will implicitly wait for aliyun to finish as well because of the pipe
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command execution failed: %w", err)
	}

	// Wait for the aliyun command to ensure it has exited cleanly
	// (Wait is called on jq, but we should still wait on aliyun to release resources)
	if err := aliyunCmd.Wait(); err != nil {
		// Note: If jq finishes successfully but aliyun returns an error (e.g., non-zero exit code),
		// this might trigger an error here. However, since jq consumed the output successfully,
		// the data was likely valid. We prioritize the jq result but log potential aliyun issues.
		// For strictness, we return the error.
		return "", fmt.Errorf("aliyun command wait failed: %w", err)
	}

	// Get the string result from the buffer
	resultStr := outBuf.String()

	// Write the captured output to the specified file
	// We use os.WriteFile to handle file creation/truncation.
	// Note: We import "os" for this operation.
	if err := os.WriteFile(outputFile, outBuf.Bytes(), 0644); err != nil {
		return resultStr, fmt.Errorf("failed to write output to file %s: %w", outputFile, err)
	}

	return resultStr, nil
}

func main() {
	// Example usage
