package main

import (
	"fmt"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	// Note: While this check helps, the best defense is avoiding shell invocation entirely (see below).
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Construct the shell command
	// SECURITY FIX: The previous implementation used `sh -c` with a formatted string,
	// which is vulnerable to command injection if inputs are not perfectly sanitized.
	// Even with the check above, complex escaping can be bypassed.
	// The secure approach is to avoid the shell and invoke commands directly with arguments.
	// However, since the requirement involves a pipeline (aliyun | jq > file), we must handle I/O redirection manually.

	// 1. Setup the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Setup the second command: jq .LoadBalancers.LoadBalancer[]
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Setup the file writer for output redirection (> output.json)
	// We use os.Create to open the file for writing. If it exists, it truncates it.
	// This mimics the '>' shell operator.
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// 4. Connect the pipeline: aliyun stdout -> jq stdin
	// We pipe the standard output of the aliyun command to the standard input of the jq command.
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe between commands: %w", err)
	}

	// 5. Connect jq stdout to the file
	jqCmd.Stdout = file

	// 6. Start the commands
	// We must start the downstream command (jq) first, or it might block waiting for input.
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Then start the upstream command (aliyun)
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// 7. Wait for commands to finish
	// Wait on aliyun first to close its stdout, signaling EOF to jq.
	if err := aliyunCmd.Wait(); err != nil {
		// Capture aliyun output if available for better error messages
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Then wait on jq to ensure it processes all data and exits.
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Return a success message. Since we redirected stdout to a file, the captured stdout is empty.
	return fmt.Sprintf("Successfully exported SLB info for '%s' to '%s'", loadBalancerName, outputFile), nil
}

