// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the command arguments securely without shell interpretation.
	// We split the pipeline into two separate commands to avoid using "sh -c",
	// which prevents shell injection vulnerabilities and improves error handling.
	// Command 1: aliyun slb DescribeLoadBalancers --LoadBalancerName <name>
	// Command 2: jq .LoadBalancers.LoadBalancer[]
	// Command 3: redirection to file (handled by Go code to avoid shell redirection issues).

	// 1. Setup the first command (Aliyun CLI)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// 2. Setup the second command (jq)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// 3. Connect the stdout of aliyunCmd to the stdin of jqCmd
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get stdout pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = aliyunStdout

	// 4. Connect the stdout of jqCmd to the output file
	jqCmd.Stdout, err = os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer jqCmd.Stdout.(*os.File).Close()

	// 5. Capture stderr from both commands for debugging
	var stderrBuf bytes.Buffer
	aliyunCmd.Stderr = &stderrBuf
	jqCmd.Stderr = &stderrBuf

	// 6. Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Process.Kill() // Kill the first process if the second fails to start
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// 7. Wait for both commands to finish
	// Important: Wait for jq first, then aliyun, to ensure proper pipe closing.
	err = jqCmd.Wait()
	if err != nil {
		aliyunCmd.Process.Kill() // Ensure aliyun process is cleaned up if jq fails
		return stderrBuf.String(), fmt.Errorf("jq command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	err = aliyunCmd.Wait()
	if err != nil {
		return stderrBuf.String(), fmt.Errorf("aliyun command failed: %w, stderr: %s", err, stderrBuf.String())
	}

	// 8. Read the generated file to return its content as the result
	content, err := os.ReadFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(content), nil
}

