// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Input validation to prevent command injection and path traversal
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>&;") {
		return "", fmt.Errorf("invalid characters in loadBalancerName")
	}
	if strings.ContainsAny(outputFile, "`$\n\r\t|>&;") || strings.Contains(outputFile, "..") {
		return "", fmt.Errorf("invalid characters or path traversal in outputFile")
	}

	// Construct the command arguments securely
	// We avoid using shell execution to prevent shell injection vulnerabilities
	// Instead, we chain commands using stdout pipes

	// Step 1: Run aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Step 2: Run jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun output to jq input
	var err error
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Capture jq output
	var jqOutput bytes.Buffer
	jqCmd.Stdout = &jqOutput

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start and wait for jq command
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Validate JSON output before writing to file
	outputData := jqOutput.Bytes()
	if !json.Valid(outputData) {
		return "", fmt.Errorf("invalid JSON output from command pipeline")
	}

	// Write to output file
	if err := os.WriteFile(outputFile, outputData, 0644); err != nil {
		return "", fmt.Errorf("failed to write to file: %w", err)
	}

	return string(outputData), nil
}

