// QuerySLBAndExport runs the aliyun CLI command to query SLB information,
// formats the output using jq, and writes the result to a specified file.
// It returns the standard output of the command execution or an error.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate that the aliyun command is available in the system PATH
	_, err := exec.LookPath("aliyun")
	if err != nil {
		return "", fmt.Errorf("aliyun CLI not found in PATH: %w", err)
	}

	// Validate that the jq command is available in the system PATH
	_, err = exec.LookPath("jq")
	if err != nil {
		return "", fmt.Errorf("jq command not found in PATH: %w", err)
	}

	// Construct the command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunArgs := []string{"slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName}
	aliyunCmd := exec.Command("aliyun", aliyunArgs...)

	// Construct the jq command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the stdout of aliyun to the stdin of jq
	// Note: In Go, we connect the streams using MultiWriter and buffers manually
	// to ensure we capture the final output for the file and the return string.

	// We need a buffer to capture the final output of the pipeline
	var outputBuffer bytes.Buffer

	// Set up the pipe: aliyun stdout -> jq stdin
	// We use a pipe for the intermediate connection
	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		return "", fmt.Errorf("failed to get stdin pipe for jq: %w", err)
	}

	// Set aliyun stdout to write to jq's stdin
	aliyunCmd.Stdout = jqStdin

	// Set jq stdout to write to our output buffer (and eventually the file)
	jqCmd.Stdout = &outputBuffer

	// Start the jq command first (it waits for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Run the aliyun command
	// We capture aliyun's stderr separately to provide better error messages
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	if err := aliyunCmd.Run(); err != nil {
		// Close the jq stdin to unblock jq if aliyun failed
		jqStdin.Close()
		// Wait for jq to finish (it will likely exit due to closed stdin)
		jqCmd.Wait()

		return "", fmt.Errorf("aliyun command failed: %w. Stderr: %s", err, aliyunStderr.String())
	}

	// Close the stdin for jq to signal end of input
	jqStdin.Close()

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Get the formatted string
	formattedOutput := outputBuffer.String()

	// Write the output to the specified file
	// Using os.Create truncates the file if it exists, or creates it if it doesn't.
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file '%s': %w", outputFile, err)
	}
	defer file.Close()

	_, err = file.WriteString(formattedOutput)
	if err != nil {
		return "", fmt.Errorf("failed to write to output file '%s': %w", outputFile, err)
	}

	return formattedOutput, nil
}

