	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to query SLB information
// and exports the result to a JSON file using jq.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate required tools
	if err := checkCommandExists("aliyun"); err != nil {
		return "", fmt.Errorf("required command 'aliyun' not found: %w", err)
	}
	if err := checkCommandExists("jq"); err != nil {
		return "", fmt.Errorf("required command 'jq' not found: %w", err)
	}

	// Build the command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	args := []string{"slb", "DescribeLoadBalancers"}
	if loadBalancerName != "" {
		args = append(args, "--LoadBalancerName", loadBalancerName)
	}

	// Execute the aliyun command
	aliyunCmd := exec.Command("aliyun", args...)

	// Capture stdout for piping to jq
	var aliyunStdout bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = os.Stderr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %w", err)
	}

	// Build the jq command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe aliyun stdout to jq stdin
	jqCmd.Stdin = &aliyunStdout

	// Capture jq stdout for writing to file
	var jqStdout bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = os.Stderr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute jq command: %w", err)
	}

	// Write the result to the output file
	if err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write to output file %s: %w", outputFile, err)
	}

	// Return the formatted output string
	return strings.TrimSpace(jqStdout.String()), nil
}

// checkCommandExists checks if a command exists in the system PATH
func checkCommandExists(cmd string) error {
	_, err := exec.LookPath(cmd)
	return err
}

// Main function to demonstrate usage
func main() {
	// Example usage (you can modify these values as needed)
	loadBalancerName := "my-load-balancer" // Set to empty string "" to query all
	outputFile := "output.json"

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Successfully exported SLB info to %s\n", outputFile)
	fmt.Println("Result preview:")
	fmt.Println(result)
}

