// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// 1. Security Fix: Remove shell invocation.
	// Instead of using exec.Command("sh", "-c", cmdStr) which is vulnerable to shell injection,
	// we execute the commands directly. This ensures that arguments are passed safely
	// to the binary and not interpreted by a shell.

	// 2. Security Fix: Remove string concatenation for the command.
	// Arguments are passed as separate strings in the variadic Args slice.
	// This prevents the loadBalancerName from being interpreted as shell commands
	// or file system operators.

	// 3. Security Fix: Handle output redirection manually.
	// Instead of using the shell operator '>', we write the output to the file
	// using Go's standard library (os.WriteFile), which is safer and more portable.

	// Step 1: Run the 'aliyun' command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Capture the standard output of the aliyun command to feed into jq
	var aliyunStdout bytes.Buffer
	aliyunCmd.Stdout = &aliyunStdout
	aliyunCmd.Stderr = &aliyunStdout // Capture errors as well

	// Execute the aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return aliyunStdout.String(), fmt.Errorf("aliyun command failed: %w", err)
	}

	// Step 2: Run the 'jq' command using the output from 'aliyun'
	// We pass the aliyun output to jq via stdin to avoid command line length limits
	// and to keep the data flow strictly between processes without shell piping.
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect aliyun's stdout to jq's stdin
	jqCmd.Stdin = bytes.NewReader(aliyunStdout.Bytes())

	// Capture jq's output
	var jqStdout bytes.Buffer
	jqCmd.Stdout = &jqStdout
	jqCmd.Stderr = &jqStdout

	// Execute the jq command
	if err := jqCmd.Run(); err != nil {
		// If jq fails, return the error and the output (which might contain the aliyun error)
		return jqStdout.String(), fmt.Errorf("jq command failed: %w", err)
	}

	// Step 3: Write the result to the output file
	// We use 0644 permissions (read/write for owner, read for others)
	// We use os.WriteFile which handles file creation/truncation safely.
	// Note: In a real application, you might want to validate outputFile to ensure it's a safe path.
	// However, since we are not invoking a shell, path traversal (e.g., ../../) is the main concern.
	// Go's os.WriteFile will write to the exact path provided.
	err := os.WriteFile(outputFile, jqStdout.Bytes(), 0644)
	if err != nil {
		return jqStdout.String(), fmt.Errorf("failed to write output file: %w", err)
	}

	// Return the standard output of the pipeline (the content written to the file)
	return jqStdout.String(), nil
}

func main() {
	// Example usage
	lbName := "my-load-balancer"
	outFile := "output.json"

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Printf("Error: %v\nOutput: %s\n", err, result)
		return
	}

	fmt.Printf("Successfully exported SLB info to %s\n", outFile)
	fmt.Printf("Command Output:\n%s\n", result)
