// QuerySLBAndExport runs the aliyun CLI command to query SLB information,
// formats it using jq, and exports the result to a specified file.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Ensure the output directory exists
	outputDir := filepath.Dir(outputFile)
	if outputDir != "." {
		if err := os.MkdirAll(outputDir, 0755); err != nil {
			return "", fmt.Errorf("failed to create output directory: %w", err)
		}
	}

	// Construct the command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]'
	// We use 'sh -c' to handle the pipe (|) functionality.
	// Note: This assumes 'aliyun' and 'jq' are installed and in the system PATH.
	command := fmt.Sprintf("aliyun slb DescribeLoadBalancers --LoadBalancerName '%s' | jq '.LoadBalancers.LoadBalancer[]'", loadBalancerName)

	// Create the command execution context
	// Using /bin/sh is standard for Linux/macOS to handle pipes. 
	// For Windows compatibility, one might use "cmd", but the requirement implies a standard Unix-like pipeline.
	cmd := exec.Command("/bin/sh", "-c", command)

	// Capture standard output and standard error
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Execute the command
	err := cmd.Run()
	if err != nil {
		// Return the standard error output if the command fails
		return "", fmt.Errorf("command execution failed: %w\nStderr: %s", err, stderr.String())
	}

	// Get the output string
	outputStr := strings.TrimSpace(stdout.String())

	// Write the output to the specified file
	// os.WriteFile creates the file if it doesn't exist or truncates it if it does.
	err = os.WriteFile(outputFile, []byte(outputStr), 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write to output file '%s': %w", outputFile, err)
	}

	// Return the output string and nil error
	return outputStr, nil
}

// main function to demonstrate usage
func main() {
	// Example usage
	lbName := "my-load-balancer" // Replace with actual name or get from args
	outFile := "output.json"

	// For demonstration, we can check if arguments are provided
	if len(os.Args) >= 3 {
		lbName = os.Args[1]
		outFile = os.Args[2]
	}

	fmt.Printf("Querying SLB: %s -> %s\n", lbName, outFile)

	result, err := QuerySLBAndExport(lbName, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Success! Result written to %s.\nContent preview:\n%s\n", outFile, result)
}

